INSERT INTO `wp_grp_google_review_text` (`id`, `review_id`, `lang`, `text`) VALUES
(1,	'50a9e8fa62abda0cbb65af6b1d667149',	'en',	'Amazing experience, extremely professional!'),
(2,	'b4c98d297781c2d9c9c5cff1a3447c45',	'en',	'This company is a total scam!! DO NOT USE.\n\nThey mis quoted prices, had the Fedarli in their pocket and totally the worst experience I\'ve ever had .'),
(3,	'98775c04d92edab85536ec0a274d4a8e',	'en',	'most ridiculous way of communication, super rude. “steffi” should take a class on how to not correspond with clients. wrote an email with when and how many people wanted to take a flight, asked if there was any special deal. no hello in the answer. all i got was a “no sorry”. just wow 👎'),
(4,	'70af1037c573efe5d4269ce1de7ea430',	'en',	'This was a fabulous experience!  We opted to take the flight from Cancun’s airport to Holbox.  Both pilots were so nice.  They even attached my GoPro to the wing of the plane.  The flights were beautiful allowing you views you don’t get to see when flying into Cancun on commercials flights.  The airport is small on Holbox and the runway is dirt.  Upon arriving, the pilot called us a taxi and waited with us until it came.  Like commercial, they offered times of availability and we selected from what they offered.  We had a lot of times from which to choose.  It was quick, convenient, and a beautiful way to get to Holbox.'),
(5,	'f9f3ac3df77350cb592ef4d7c5f39423',	'en',	'At time, good pilot, perfect plane');
