(1051,	'_transient_grw_feed_6.9.8_90_reviews',	'a:3:{s:10:\"businesses\";a:1:{i:0;O:8:\"stdClass\":8:{s:2:\"id\";s:27:\"ChIJXRS9Mm2TTY8RTJzi_FLzeXQ\";s:4:\"name\";s:14:\"Flights Holbox\";s:3:\"url\";s:114:\"https://maps.google.com/?cid=8393006918337207372&g_mp=CiVnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLkdldFBsYWNlEAIYBCAA\";s:5:\"photo\";s:87:\"http://flightsholboxv1.local/wp-content/uploads/2026/07/ChIJXRS9Mm2TTY8RTJzi_FLzeXQ.jpg\";s:7:\"address\";s:82:\"Calle Av Damero Calle Sierra next to Luuma Holbox Island, 77310 Isla, Q.R., Mexico\";s:6:\"rating\";s:3:\"3.7\";s:12:\"review_count\";s:1:\"6\";s:8:\"provider\";s:6:\"google\";}}s:7:\"reviews\";a:4:{i:0;O:8:\"stdClass\":15:{s:2:\"id\";s:1:\"1\";s:4:\"hide\";s:0:\"\";s:6:\"biz_id\";s:27:\"ChIJXRS9Mm2TTY8RTJzi_FLzeXQ\";s:7:\"biz_url\";s:114:\"https://maps.google.com/?cid=8393006918337207372&g_mp=CiVnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLkdldFBsYWNlEAIYBCAA\";s:6:\"rating\";s:1:\"5\";s:4:\"text\";s:43:\"Amazing experience, extremely professional!\";s:13:\"author_avatar\";s:120:\"http://flightsholboxv1.local/wp-content/uploads/2026/07/ChIJXRS9Mm2TTY8RTJzi_FLzeXQ_12139ba280f20746161069b90e519cc3.jpg\";s:10:\"author_url\";s:65:\"https://www.google.com/maps/contrib/106554214530259303234/reviews\";s:11:\"author_name\";s:13:\"Taylor Cloete\";s:4:\"time\";s:10:\"1683149494\";s:6:\"images\";N;s:5:\"reply\";N;s:10:\"reply_time\";N;s:3:\"url\";N;s:8:\"provider\";s:6:\"google\";}i:1;O:8:\"stdClass\":15:{s:2:\"id\";s:1:\"4\";s:4:\"hide\";s:0:\"\";s:6:\"biz_id\";s:27:\"ChIJXRS9Mm2TTY8RTJzi_FLzeXQ\";s:7:\"biz_url\";s:114:\"https://maps.google.com/?cid=8393006918337207372&g_mp=CiVnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLkdldFBsYWNlEAIYBCAA\";s:6:\"rating\";s:1:\"5\";s:4:\"text\";s:631:\"This was a fabulous experience!  We opted to take the flight from Cancun’s airport to Holbox.  Both pilots were so nice.  They even attached my GoPro to the wing of the plane.  The flights were beautiful allowing you views you don’t get to see when flying into Cancun on commercials flights.  The airport is small on Holbox and the runway is dirt.  Upon arriving, the pilot called us a taxi and waited with us until it came.  Like commercial, they offered times of availability and we selected from what they offered.  We had a lot of times from which to choose.  It was quick, convenient, and a beautiful way to get to Holbox.\";s:13:\"author_avatar\";s:120:\"http://flightsholboxv1.local/wp-content/uploads/2026/07/ChIJXRS9Mm2TTY8RTJzi_FLzeXQ_20691f18acecab944ec23817530a1125.jpg\";s:10:\"author_url\";s:65:\"https://www.google.com/maps/contrib/108542397756045958288/reviews\";s:11:\"author_name\";s:7:\"Ali Bug\";s:4:\"time\";s:10:\"1641500153\";s:6:\"images\";N;s:5:\"reply\";N;s:10:\"reply_time\";N;s:3:\"url\";N;s:8:\"provider\";s:6:\"google\";}i:2;O:8:\"stdClass\":15:{s:2:\"id\";s:1:\"5\";s:4:\"hide\";s:0:\"\";s:6:\"biz_id\";s:27:\"ChIJXRS9Mm2TTY8RTJzi_FLzeXQ\";s:7:\"biz_url\";s:114:\"https://maps.google.com/?cid=8393006918337207372&g_mp=CiVnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLkdldFBsYWNlEAIYBCAA\";s:6:\"rating\";s:1:\"5\";s:4:\"text\";N;s:13:\"author_avatar\";s:120:\"http://flightsholboxv1.local/wp-content/uploads/2026/07/ChIJXRS9Mm2TTY8RTJzi_FLzeXQ_94e980a40387efde9305102449c51a87.jpg\";s:10:\"author_url\";s:65:\"https://www.google.com/maps/contrib/115892358014145715107/reviews\";s:11:\"author_name\";s:12:\"Yael Rosales\";s:4:\"time\";s:10:\"1624499804\";s:6:\"images\";N;s:5:\"reply\";N;s:10:\"reply_time\";N;s:3:\"url\";N;s:8:\"provider\";s:6:\"google\";}i:3;O:8:\"stdClass\":15:{s:2:\"id\";s:1:\"6\";s:4:\"hide\";s:0:\"\";s:6:\"biz_id\";s:27:\"ChIJXRS9Mm2TTY8RTJzi_FLzeXQ\";s:7:\"biz_url\";s:114:\"https://maps.google.com/?cid=8393006918337207372&g_mp=CiVnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLkdldFBsYWNlEAIYBCAA\";s:6:\"rating\";s:1:\"5\";s:4:\"text\";s:34:\"At time, good pilot, perfect plane\";s:13:\"author_avatar\";s:120:\"http://flightsholboxv1.local/wp-content/uploads/2026/07/ChIJXRS9Mm2TTY8RTJzi_FLzeXQ_11f69f54d1f6f84e726c4d2970a6a92d.jpg\";s:10:\"author_url\";s:65:\"https://www.google.com/maps/contrib/102505746536836513945/reviews\";s:11:\"author_name\";s:8:\"Oliver H\";s:4:\"time\";s:10:\"1614030269\";s:6:\"images\";N;s:5:\"reply\";N;s:10:\"reply_time\";N;s:3:\"url\";N;s:8:\"provider\";s:6:\"google\";}}s:7:\"options\";O:8:\"stdClass\":53:{s:9:\"view_mode\";s:6:\"slider\";s:10:\"pagination\";s:0:\"\";s:9:\"text_size\";s:0:\"\";s:13:\"header_center\";b:0;s:17:\"header_hide_photo\";b:0;s:16:\"header_hide_name\";b:0;s:13:\"hide_based_on\";b:0;s:16:\"hide_writereview\";b:0;s:15:\"short_last_name\";b:0;s:10:\"min_letter\";b:0;s:18:\"header_hide_social\";b:0;s:12:\"slider_speed\";s:0:\"\";s:18:\"slider_text_height\";s:0:\"\";s:15:\"slider_autoplay\";b:1;s:16:\"slider_mousestop\";b:1;s:20:\"slider_hide_prevnext\";b:0;s:16:\"slider_hide_dots\";b:0;s:18:\"slider_breakpoints\";s:0:\"\";s:4:\"null\";s:3:\"off\";s:0:\"\";s:1:\"3\";s:12:\"--star-color\";s:7:\"#fb8e28\";s:17:\"--head-name-color\";s:7:\"#333333\";s:18:\"--head-based-color\";s:7:\"#555555\";s:15:\"--powered-color\";s:7:\"#777777\";s:11:\"--btn-color\";s:7:\"#1f67e7\";s:11:\"--rev-color\";b:0;s:12:\"--name-color\";s:7:\"#154fc1\";s:12:\"--text-color\";s:7:\"#222222\";s:10:\"dark_theme\";b:0;s:10:\"show_round\";b:1;s:11:\"show_shadow\";b:0;s:10:\"style_vars\";s:0:\"\";s:13:\"lazy_load_img\";b:1;s:13:\"nofollow_link\";b:1;s:9:\"open_link\";b:1;s:10:\"aria_label\";b:0;s:5:\"media\";b:1;s:5:\"reply\";b:1;s:19:\"google_def_rev_link\";b:0;s:20:\"reviewer_avatar_size\";s:2:\"56\";s:5:\"cache\";s:2:\"12\";s:13:\"reviews_limit\";s:0:\"\";s:6:\"hidden\";s:3:\"2,3\";s:17:\"disable_user_link\";b:0;s:12:\"hide_reviews\";b:0;s:11:\"hide_avatar\";b:0;s:12:\"hide_backgnd\";b:0;s:18:\"slider_hide_border\";b:0;s:19:\"header_merge_social\";b:0;s:8:\"centered\";b:0;s:9:\"max_width\";s:0:\"\";s:10:\"max_height\";s:0:\"\";s:10:\"star_style\";s:0:\"\";}}',	'off'),
