(23,	1,	'2026-07-02 12:53:57',	'2026-07-02 11:53:57',	'<!-- wp:acf/hero-panel {\"name\":\"acf/hero-panel\",\"data\":{\"hero_slides_0_slide_image\":84,\"_hero_slides_0_slide_image\":\"field_6a465a86ac589\",\"hero_slides_1_slide_image\":85,\"_hero_slides_1_slide_image\":\"field_6a465a86ac589\",\"hero_slides_2_slide_image\":86,\"_hero_slides_2_slide_image\":\"field_6a465a86ac589\",\"hero_slides\":3,\"_hero_slides\":\"field_6a465a79ac588\",\"hero_heading\":\"Private Air Taxi Cancun to Holbox\",\"_hero_heading\":\"field_6a465aa9ac58a\",\"hero_intro\":\"Fly in Just 30 Minutes\",\"_hero_intro\":\"field_6a465ab2ac58b\",\"hero_logo\":302,\"_hero_logo\":\"field_6a465ac0ac58c\"},\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/booking-panel {\"name\":\"acf/booking-panel\",\"data\":{\"sister_site_url\":\"https://goholboxtransfers.com/\",\"_sister_site_url\":\"field_6a465a2f24a91\",\"sister_site_label\":\"Book a land transfer\",\"_sister_site_label\":\"field_6a465a4a24a92\"},\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/text-panel {\"name\":\"acf/text-panel\",\"data\":{\"content\":\"\\u003ch2 class=\\u0022section-heading small-bot\\u0022 style=\\u0022text-align: center;\\u0022\\u003e\\u003cspan style=\\u0022color: #00467b;\\u0022\\u003ePrivate Flights Cancun to Holbox- Book Your Air Taxi\\u003c/span\\u003e\\u003c/h2\\u003e\\r\\n\\u003ch4 class=\\u0022tiny-bot\\u0022 style=\\u0022text-align: center;\\u0022\\u003e\\u003cspan style=\\u0022color: #888888;\\u0022\\u003ePrivate Air Taxi from Cancún to Holbox, Cozumel, Playa del Carmen, Merida and many more destinations.\\u003c/span\\u003e\\u003c/h4\\u003e\\r\\n\\u003cp style=\\u0022text-align: center;\\u0022\\u003eWe pride ourselves on being professional and efficient. Flights-Holbox is one of the few operators in the Riviera Maya offering a fully licensed private air taxi service with more than 17 years of experience. Whether you need a private air taxi from Cancun to Holbox or flights to Cozumel, Merida or Playa del Carmen, we have you covered.\\u003c/p\\u003e\\r\\n\\u003cp style=\\u0022text-align: center;\\u0022\\u003eWe will make sure you get the best service possible because the last thing you need is stressing about your transfer. It\'s so important to choose a professional, experienced and safe operator.\\u003c/p\\u003e\",\"_content\":\"field_6a465ad18514f\",\"text_alignment\":\"center\",\"_text_alignment\":\"field_6a47a299896e2\",\"background_colour\":\"\",\"_background_colour\":\"field_69fb291d7099f\",\"container_size\":\"\",\"_container_size\":\"field_6a104fa067637\",\"panel_settings\":\"\",\"_panel_settings\":\"field_6a47a682138e0\"},\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/text-panel {\"name\":\"acf/text-panel\",\"data\":{\"content\":\"\\u003ch3\\u003e\\u003cspan style=\\u0022color: #888888;\\u0022\\u003eBook at least 24 hours ahead to secure your flight. Available daily 9am–6pm.\\u003c/span\\u003e\\u003c/h3\\u003e\",\"_content\":\"field_6a465ad18514f\",\"text_alignment\":\"center\",\"_text_alignment\":\"field_6a47a299896e2\",\"background_colour\":\"white\",\"_background_colour\":\"field_69fb291d7099f\",\"container_size\":\"medium\",\"_container_size\":\"field_6a104fa067637\",\"panel_settings\":\"\",\"_panel_settings\":\"field_6a47a682138e0\"},\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/slider-panel {\"name\":\"acf/slider-panel\",\"data\":{\"slider_heading\":\"Airports we fly to\",\"_slider_heading\":\"field_6a47ba31b36fd\",\"slider_intro\":\"This is a slider intro. This is a slider intro. This is a slider intro. This is a slider intro. This is a slider intro. This is a slider intro. This is a slider intro. This is a slider intro. This is a slider intro. This is a slider intro. \",\"_slider_intro\":\"field_6a47ba60b36fe\",\"slider_items_0_slide_post\":134,\"_slider_items_0_slide_post\":\"field_6a47ba81b3700\",\"slider_items_0_button_button_link\":{\"title\":\"Read More\",\"url\":\"http://flightsholboxv1.local/airports/holbox/\",\"target\":\"\"},\"_slider_items_0_button_button_link\":\"field_6a10337e94d01\",