(303,	1,	'2026-07-06 19:36:25',	'2026-07-06 18:36:25',	'<!-- wp:acf/hero-panel {\"name\":\"acf/hero-panel\",\"data\":{\"hero_slides_0_slide_image\":84,\"_hero_slides_0_slide_image\":\"field_6a465a86ac589\",\"hero_slides_1_slide_image\":85,\"_hero_slides_1_slide_image\":\"field_6a465a86ac589\",\"hero_slides_2_slide_image\":86,\"_hero_slides_2_slide_image\":\"field_6a465a86ac589\",\"hero_slides\":3,\"_hero_slides\":\"field_6a465a79ac588\",\"hero_heading\":\"Private Air Taxi Cancun to Holbox\",\"_hero_heading\":\"field_6a465aa9ac58a\",\"hero_intro\":\"Fly in Just 30 Minutes\",\"_hero_intro\":\"field_6a465ab2ac58b\",\"hero_logo\":302,\"_hero_logo\":\"field_6a465ac0ac58c\"},\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/booking-panel {\"name\":\"acf/booking-panel\",\"data\":{\"sister_site_url\":\"https://goholboxtransfers.com/\",\"_sister_site_url\":\"field_6a465a2f24a91\",\"sister_site_label\":\"Book a land transfer\",\"_sister_site_label\":\"field_6a465a4a24a92\"},\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/text-panel {\"name\":\"acf/text-panel\",\"data\":{\"content\":\"\\u003ch2 class=\\u0022section-heading small-bot\\u0022 style=\\u0022text-align: center;\\u0022\\u003e\\u003cspan style=\\u0022color: #00467b;\\u0022\\u003ePrivate Flights Cancun to Holbox- Book Your Air Taxi\\u003c/span\\u003e\\u003c/h2\\u003e\\r\\n\\u003ch4 class=\\u0022tiny-bot\\u0022 style=\\u0022text-align: center;\\u0022\\u003e\\u003cspan style=\\u0022color: #888888;\\u0022\\u003ePrivate Air Taxi from Cancún to Holbox, Cozumel, Playa del Carmen, Merida and many more destinations.\\u003c/span\\u003e\\u003c/h4\\u003e\\r\\n\\u003cp style=\\u0022text-align: center;\\u0022\\u003eWe pride ourselves on being professional and efficient. Flights-Holbox is one of the few operators in the Riviera Maya offering a fully licensed private air taxi service with more than 17 years of experience. Whether you need a private air taxi from Cancun to Holbox or flights to Cozumel, Merida or Playa del Carmen, we have you covered.\\u0