7637\",\"panel_settings\":\"\",\"_panel_settings\":\"field_6a4b900f65ba7\"},\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/table-panel {\"name\":\"acf/table-panel\",\"data\":{\"table_heading\":\"To Cancun\",\"_table_heading\":\"field_6a4b8f4c65b9d\",\"table_intro\":\"This is a test intro\",\"_table_intro\":\"field_6a4b8f5965b9e\",\"column_1_label\":\"Small Plane \",\"_column_1_label\":\"field_6a4b8f6265b9f\",\"column_1_sublabel\":\"Up to 5 people (Max 330Kg) (USD)\",\"_column_1_sublabel\":\"field_6a4b8f8765ba0\",\"column_2_label\":\"Larger Plane \",\"_column_2_label\":\"field_6a4b8f9d65ba1\",\"column_2_sublabel\":\"Up to 13 people (Max 900Kg) (USD)\",\"_column_2_sublabel\":\"field_6a4b8fae65ba2\",\"rows_0_row_label\":\"Holbox\",\"_rows_0_row_label\":\"field_6a4b8fc565ba4\",\"rows_0_column_1_value\":\"$100\",\"_rows_0_column_1_value\":\"field_6a4b8fcf65ba5\",\"rows_0_column_2_value\":\"$100\",\"_rows_0_column_2_value\":\"field_6a4b8fdb65ba6\",\"rows_1_row_label\":\"Cozumel\",\"_rows_1_row_label\":\"field_6a4b8fc565ba4\",\"rows_1_column_1_value\":\"$100\",\"_rows_1_column_1_value\":\"field_6a4b8fcf65ba5\",\"rows_1_column_2_value\":\"$100\",\"_rows_1_column_2_value\":\"field_6a4b8fdb65ba6\",\"rows_2_row_label\":\"Cancun\",\"_rows_2_row_label\":\"field_6a4b8fc565ba4\",\"rows_2_column_1_value\":\"$100\",\"_rows_2_column_1_value\":\"field_6a4b8fcf65ba5\",\"rows_2_column_2_value\":\"$100\",\"_rows_2_column_2_value\":\"field_6a4b8fdb65ba6\",\"rows\":3,\"_rows\":\"field_6a4b8fbf65ba3\",\"background_colour\":\"light-grey\",\"_background_colour\":\"field_69fb291d7099f\",\"container_size\":\"medium\",\"_container_size\":\"field_6a104fa067637\",\"panel_settings\":\"\",\"_panel_settings\":\"field_6a4b900f65ba7\"},\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/text-column-panel {\"name\":\"acf/text-column-panel\",\"data\":{\"heading\":\"This is a test heading\",\"_heading\":\"field_6a48c9e16d855\",\"columns_0_column_content\":\"\\u003cp class=\\u0022intro\\u0022\\u003e\\u003cspan style=\\u0022color: #888888;\\u0022\\u003eWe will make sure you get the best service as possible because the last thing you need is to feel stressed about your transfer. We are a professional, experienced and safe operator.\\u003c/span\\u003e\\u003c/p\\u003e\\r\\nFlights-Holbox is one of the few operators in the Riviera Maya offering fully licensed flights (air taxis) or vans (ground transfer) with more the 17 years of experience. Book your private air plane between Cancun, Holbox, Cozumel or Playa del Carmen.\",\"_columns_0_column_content\":\"field_6a48ca046d857\",\"columns_1_column_content\":\"\\u003cul class=\\u0022styled-list\\u0022\\u003e\\r\\n \\t\\u003cli\\u003eOur private planes only fly between 7:00 and 17:30. Flight times can change depend on season and day light.Its not possible to fly to Holbox at night.\\u003c/li\\u003e\\r\\n \\t\\u003cli\\u003eFlights Holbox use the FBO at the International Airport of Cancún.\\u003c/li\\u003e\\r\\n \\t\\u003cli\\u003eChanging terminals in Cancun requires a prebooked Taxi- we can help you setting up your taxi.\\u003c/li\\u003e\\r\\n \\t\\u003cli\\u003eTaking a taxi cost around 20-30 USD. (5 min ride)\\u003c/li\\u003e\\r\\n \\t\\u003cli\\u003eIf you\'re flying out of Cancún airport you\'ll need to pay an airport tax of around 10 USD - unless you\'re flying into and out of Cancún airport on the same day.\\u003c/li\\u003e\\r\\n \\t\\u003cli\\u003eThere are only a few ATMs on Isla Holbox, we suggest to bring enough cash to the island.\\u003c/li\\u003e\\r\\n \\t\\u003cli\\u003eWe accept card payments, cash, bank transfer or Paypal.\\u003c/li\\u003e\\r\\n \\t\\u003cli\\u003eYou can get to FBO airport in Cancún only by taxi you can\'t walk.\\u003c/li\\u003e\\r\\n\\u003c/ul\\u003e\",\"_columns_1_column_content\":\"field_6a48ca046d857\",\"columns\":2,\"_columns\":\"field_6a48c9ed6d856\"},\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/socials-panel {\"name\":\"acf/socials-panel\",\"data\":{\"heading\":\"Follow Our Socials\",\"_heading\":\"field_6a48c9641e8c0\",\"socials_0_platform\":\"facebook\",\"_socials_0_platform\":\"field_6a48c9891e8c2\",\"socials_0_url\":\"https://www.facebook.com/\",\"_socials_0_url\":\"field_6a48c9c51e8c3\",\"socials_1_platform\":\"instagram\",\"_socials_1_platform\":\"field_6a48c9891e8c2\",\"socials_1_url\":\"https://www.instagram.com/\",\"_socials_1_url\":\"field_6a48c9c51e8c3\",\"socials\":2,\"_socials\":\"field_6a48c97a1e8c1\"},\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/route-map-panel {\"name\":\"acf/route-map-panel\",\"data\":{\"route_map_heading\":\"This is a heading\",\"_route_map_heading\":\"field_6a4d2d2aabb82\"},\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/tripadvisor-panel {\"name\":\"acf/tripadvisor-panel\",\"data\":{\"heading\":\"This is a heading\",\"_heading\":\"field_6a4eb753d02cb\",\"description\":\"This is a description\",\"_description\":\"field_6a4eb96ad02cc\",\"button_link_button_link\":{\"title\":\"Find out more\",\"url\":\"#\",\"target\":\"\"},\"_button_link_button_link\":\"field_6a10337e94d01\",\"button_link_button_colour\":\"white\",\"_button_link_button_colour\":\"field_69fb154a3681d\",\"button_link\":\"\",\"_button_link\":\"field_6a4eb972d02cd\",\"background_colour\":\"\",\"_background_colour\":\"field_69fb291d7099f\",\"container_size\":\"\",\"_container_size\":\"field_6a104fa067637\",\"panel_settings\":\"\",\"_panel_settings\":\"field_6a4eb99ed02ce\"},\"mode\":\"edit\"} /-->',	'Test',	'',	'inherit',	'closed',	'closed',	'',	'257-revision-v1',	'',	'',	'2026-07-08 22:00:42',	'2026-07-08 21:00:42',	'',	257,	'http://flightsholboxv1.local/?p=349',	0,	'revision',	'',	0),
